```javascript
const fs = require("fs");
const http = require("http");
const WebSocket = require("ws");
const path = require("path");
const url = require("url");
const { v4: uuidv4 } = require("uuid");

// 直接设置静态文件服务的目录为C:\wwwroot\uploads
const staticBasePath = "C:\\wwwroot\\uploads";

// 创建HTTP服务器
const server = http.createServer((req, res) => {
    // 解析请求的URL
    const parsedUrl = url.parse(req.url);
    let pathname = path.join(staticBasePath, parsedUrl.pathname);

    // 检查文件是否存在
    fs.exists(pathname, exist => {
        if (!exist) {
            res.statusCode = 404;
            res.end(`文件 ${pathname} 未找到!`);
            return;
        }

        // 读取并返回文件
        fs.readFile(pathname, (err, data) => {
            if (err) {
                res.statusCode = 500;
                res.end(`无法读取文件: ${err}.`);
                return;
            }

            res.setHeader("Content-Type", getMimeType(pathname));
            res.end(data);
        });
    });
});

// 创建WebSocket服务器
const wss = new WebSocket.Server({ server });

wss.on("connection", ws => {
    ws.on("message", message => {
        try {
            const data = JSON.parse(message);

            if (data.type === "text") {
                // 广播文本消息
                broadcast(message);
            } else if (data.type === "file") {
                // 处理文件上传
                let base64Data = data.filedata.split(";base64,").pop();
                const filename = `${uuidv4()}${path.extname(data.originalName)}`;
                const filepath = path.join(staticBasePath, filename);

                // 保存解码后的文件
                fs.writeFile(filepath, base64Data, 'base64', err => {
                    if (err) {
                        console.error("File could not be saved: ", err);
                        ws.send(JSON.stringify({ type: "error", message: "File could not be saved" }));
                        return;
                    }

                    // 生成正确的下载链接
                    const fileUrl = `http://${req.headers.host}/uploads/${filename}`;
                    broadcast(JSON.stringify({
                        type: "file",
                        name: data.name,
                        originalName: data.originalName,
                        url: fileUrl
                    }));
                });
            }
        } catch (e) {
            console.error('Error parsing JSON: ', e);
        }
    });
});

// 根据文件路径获取MIME类型的函数
function getMimeType(filePath) {
    const ext = path.extname(filePath).toLowerCase();
    const mimeTypes = {
        '.html': 'text/html',
        '.css': 'text/css',
        '.js': 'application/javascript',
        '.json': 'application/json',
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        // add more as needed
    };
    return mimeTypes[ext] || "application/octet-stream";
}

// 广播消息到所有客户端的函数
function broadcast(message) {
    wss.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
            client.send(message);
        }
    });
}

const PORT = 3000;
server.listen(PORT, () => {
    console.log(`Server is running at http://localhost:${PORT}`);
});
```

注意：

1. 此代码假定静态文件服务的目录是`C:\wwwroot\uploads`，并且您的服务器可以通过网络路径提供这些文件。请确保服务器的HTTP服务配置正确，能够访问此目录。
2. 请将`http://${req.headers.host}/uploads/${filename}`中的`${req.headers.host}`替换为您服务器的实际地址，如果您使用了NAT或代理，请将它替换为正确的公网地址。
3. 以上代码未包含错误处理，例如HTTP请求头中可能不存在`host`。实际使用中应当添加相应的错误处理。
4. 若要让外部设备能够通过网络下载这些文件，请确保您的服务器配置正确地将`C:\wwwroot\uploads`作为静态文件目录对外部提供服务，并且配置了正确的网络防火墙和路由规则。
